import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { MapContainer, TileLayer, Marker } from "react-leaflet";
import L from "leaflet";
import api from "../utils/api";

const DAYS = ["Ням","Даваа","Мягмар","Лхагва","Пүрэв","Баасан","Бямба"];

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require("leaflet/dist/images/marker-icon-2x.png"),
  iconUrl:       require("leaflet/dist/images/marker-icon.png"),
  shadowUrl:     require("leaflet/dist/images/marker-shadow.png"),
});

export default function BusinessPage() {
  const { id } = useParams();
  const nav = useNavigate();
  const [biz, setBiz]         = useState(null);
  const [tab, setTab]         = useState("service");
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    api.get(`/businesses/${id}`).then(({ data }) => { setBiz(data.data); setLoading(false); });
  }, [id]);

  if (loading) return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:400, color:"var(--muted)" }}>
      Ачаалж байна...
    </div>
  );
  if (!biz) return <div style={{ padding:40, color:"var(--red)" }}>Байгууллага олдсонгүй</div>;

  const today = new Date().getDay();
  const todaySched = biz.schedules?.find(s => s.day === today);

  return (
    <div style={{ maxWidth:1100, margin:"0 auto", padding:"24px 20px" }}>
      {/* Hero */}
      <div style={{
        borderRadius:16, overflow:"hidden", position:"relative", height:320,
        background:"var(--card)", marginBottom:24,
      }}>
        {biz.images?.[0] ? (
          <img src={biz.images[0]} alt={biz.name}
            style={{ width:"100%", height:"100%", objectFit:"cover" }} />
        ) : (
          <div style={{ height:"100%", display:"flex", alignItems:"center",
            justifyContent:"center", fontSize:80, color:"var(--muted)" }}>📍</div>
        )}
        {/* Overlay */}
        <div style={{
          position:"absolute", bottom:0, left:0, right:0,
          background:"linear-gradient(transparent, rgba(0,0,0,0.85))",
          padding:"60px 24px 24px",
        }}>
          <div style={{
            display:"inline-block", padding:"3px 10px", borderRadius:20,
            background:"var(--teal)", color:"#fff", fontSize:11, fontWeight:600,
            marginBottom:8, textTransform:"uppercase", letterSpacing:"0.05em",
          }}>
            {biz.category}
          </div>
          <div style={{ fontSize:32, fontWeight:800, color:"#fff" }}>{biz.name}</div>
          <div style={{ color:"rgba(255,255,255,0.7)", marginTop:4 }}>📍 {biz.address}</div>
          <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:8 }}>
            <span style={{ color:"#F59E0B" }}>⭐</span>
            <span style={{ color:"#fff", fontWeight:700, fontSize:16 }}>{biz.rating}</span>
            <span style={{ color:"rgba(255,255,255,0.6)", fontSize:13 }}>({biz.reviewCount} үнэлгээ)</span>
            {todaySched && !todaySched.isClosed && (
              <span style={{ marginLeft:8, color:"var(--green)", fontSize:13 }}>
                ● Нээлттэй {todaySched.openTime}–{todaySched.closeTime}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Layout */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 320px", gap:20 }}>
        {/* Left tabs */}
        <div>
          <div style={{ display:"flex", gap:4, marginBottom:20, borderBottom:"1px solid var(--border)", paddingBottom:0 }}>
            {[["service","Үйлчилгээ"],["schedule","Цагийн хуваарь"],["location","Байршил"],["info","Дэлгэрэнгүй"]].map(([k,l]) => (
              <button key={k} onClick={()=>setTab(k)} style={{
                padding:"10px 20px", background:"none", border:"none",
                cursor:"pointer", fontSize:14, fontWeight:500,
                color: tab===k ? "var(--text)" : "var(--muted)",
                borderBottom: tab===k ? "2px solid var(--blue)" : "2px solid transparent",
                marginBottom:-1, transition:"all .15s",
              }}>{l}</button>
            ))}
          </div>

          {/* Services tab */}
          {tab === "service" && (
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {biz.services?.length === 0 && <div style={{ color:"var(--muted)" }}>Үйлчилгээ байхгүй</div>}
              {biz.services?.map(s => (
                <div key={s._id} onClick={()=>setSelected(s._id)}
                  style={{
                    display:"flex", alignItems:"center", gap:14,
                    padding:"14px 16px", borderRadius:10,
                    background: selected===s._id ? "rgba(37,99,235,0.1)" : "var(--card)",
                    border:"1px solid", borderColor: selected===s._id ? "var(--blue)" : "var(--border)",
                    cursor:"pointer", transition:"all .15s",
                  }}>
                  <div style={{
                    width:48, height:48, borderRadius:10,
                    background:"var(--surface)", display:"flex",
                    alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0,
                  }}>✂</div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:600, fontSize:14 }}>{s.name}</div>
                    <div style={{ fontSize:12, color:"var(--muted)", marginTop:3 }}>
                      ⏱ {s.duration} мин
                    </div>
                  </div>
                  <div style={{ textAlign:"right" }}>
                    <div style={{ fontWeight:700, fontSize:16, color:"var(--blue)" }}>
                      {s.price > 0 ? `₮${s.price.toLocaleString()}` : "Үнэгүй"}
                    </div>
                    <div style={{ fontSize:11, color:"var(--muted)", marginTop:2 }}>НӨТ орсон</div>
                  </div>
                  <span style={{ fontSize:20, color:"var(--muted)" }}>+</span>
                </div>
              ))}
            </div>
          )}

          {/* Schedule tab */}
          {tab === "schedule" && (
            <div className="card" style={{ padding:0, overflow:"hidden" }}>
              {DAYS.map((day, i) => {
                const s = biz.schedules?.find(sc => sc.day === i);
                const isToday = i === today;
                return (
                  <div key={i} style={{
                    display:"flex", justifyContent:"space-between", alignItems:"center",
                    padding:"14px 20px",
                    background: isToday ? "rgba(37,99,235,0.08)" : "transparent",
                    borderBottom: i < 6 ? "1px solid var(--border)" : "none",
                  }}>
                    <span style={{ fontWeight: isToday ? 600 : 400, fontSize:14,
                      color: isToday ? "var(--text)" : "var(--muted)" }}>
                      {isToday && "→ "}{day}
                    </span>
                    {s?.isClosed ? (
                      <span style={{ color:"var(--red)", fontSize:13 }}>Амарна</span>
                    ) : (
                      <span style={{ color: isToday ? "var(--green)" : "var(--muted)", fontSize:13 }}>
                        {s?.openTime} – {s?.closeTime}
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {/* Location tab */}
          {tab === "location" && (
            <div>
              <div style={{ height:300, borderRadius:12, overflow:"hidden", marginBottom:16 }}>
                <MapContainer center={[biz.location.lat, biz.location.lng]} zoom={15}
                  style={{ width:"100%", height:"100%" }} zoomControl={false}>
                  <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                  <Marker position={[biz.location.lat, biz.location.lng]} />
                </MapContainer>
              </div>
              <div className="card">
                <div style={{ fontSize:13, color:"var(--muted)", marginBottom:4 }}>Хаяг</div>
                <div>{biz.address}</div>
                {biz.phone && (
                  <div style={{ marginTop:8, color:"var(--muted)", fontSize:13 }}>📞 {biz.phone}</div>
                )}
              </div>
            </div>
          )}

          {/* Info tab */}
          {tab === "info" && (
            <div className="card">
              <div style={{ lineHeight:1.7, color:"var(--muted)", fontSize:14 }}>
                {biz.description || "Дэлгэрэнгүй мэдээлэл байхгүй."}
              </div>
            </div>
          )}
        </div>

        {/* Right sticky panel */}
        <div>
          <div className="card" style={{ position:"sticky", top:80 }}>
            <div style={{ fontSize:13, color:"var(--muted)", marginBottom:12 }}>Сонгосон үйлчилгээ</div>
            {selected ? (
              <>
                {(() => {
                  const s = biz.services?.find(s=>s._id===selected);
                  return s ? (
                    <div>
                      <div style={{ fontWeight:600, marginBottom:4 }}>{s.name}</div>
                      <div style={{ fontSize:13, color:"var(--muted)" }}>⏱ {s.duration} мин</div>
                      <div style={{ fontSize:20, fontWeight:700, color:"var(--blue)", marginTop:8 }}>
                        ₮{s.price.toLocaleString()}
                      </div>
                    </div>
                  ) : null;
                })()}
              </>
            ) : (
              <div style={{ fontSize:13, color:"var(--muted)" }}>Үйлчилгээ сонгоно уу</div>
            )}
            <button
              onClick={() => nav(`/book/${id}${selected ? `?serviceId=${selected}` : ""}`)}
              className="btn btn-primary"
              style={{ width:"100%", marginTop:16, padding:"12px 0", fontSize:15, fontWeight:600 }}
            >📅 Цаг захиалах</button>
          </div>
        </div>
      </div>
    </div>
  );
}
